#include <stdio.h>
#include <stdlib.h>

typedef struct {int start; int end;} Interval;

int compare(const void *a, const void *b) {
    const Interval *i1 = (const Interval *)a;
    const Interval *i2 = (const Interval *)b;
    return i1->start - i2->start;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Interval *arr = malloc(N * sizeof(Interval));
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &arr[i].start, &arr[i].end);
        }
        qsort(arr, N, sizeof(Interval), compare);
        int curL = arr[0].start, curR = arr[0].end;
        for (int i = 1; i < N; ++i) {
            if (arr[i].start <= curR) {
                if (arr[i].end > curR) curR = arr[i].end;
            } else {
                printf("[%d %d] ", curL, curR);
                curL = arr[i].start;
                curR = arr[i].end;
            }
        }
        printf("[%d %d]\n", curL, curR);
        free(arr);
    }
    return 0;
}

