import java.io.*;
import java.util.*;

public class Main {
    static class Interval {
        int start, end;
        Interval(int s, int e) { start = s; end = e; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Interval[] arr = new Interval[N];
            for (int i = 0; i < N; i++) {
                st = new StringTokenizer(br.readLine());
                int s = Integer.parseInt(st.nextToken());
                int e = Integer.parseInt(st.nextToken());
                arr[i] = new Interval(s, e);
            }
            Arrays.sort(arr, Comparator.comparingInt(a -> a.start));
            int curL = arr[0].start, curR = arr[0].end;
            for (int i = 1; i < N; i++) {
                if (arr[i].start <= curR) {
                    if (arr[i].end > curR) curR = arr[i].end;
                } else {
                    out.append('[').append(curL).append(' ').append(curR).append("] ");
                    curL = arr[i].start;
                    curR = arr[i].end;
                }
            }
            out.append('[').append(curL).append(' ').append(curR).append("]\n");
        }
        System.out.print(out.toString());
    }
}

