  }
  intervals.sort((a, b) => a[0] - b[0]);
  let merged = [];
  for (let i = 0; i < intervals.length; i++) {
    const [s, e] = intervals[i];
    if (merged.length === 0 || s > merged[merged.length - 1][1]) {
      merged.push([s, e]);
    } else {
      merged[merged.length - 1][1] = Math.max(merged[merged.length - 1][1], e);
    }
